(815, 1, 242, 21, NULL, 'Paderborn', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
(816, 1, 242, 21, NULL, 'Dornhagen', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
(817, 1, 242, 21, NULL, 'Grondsteinheim', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
(818, 1, 242, 21, NULL, 'Lichtenau', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
(819, 1, 242, 21, NULL, 'Kleinenberg', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
(820, 1, 242, 21, NULL, 'Hardehauserwoud', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
(821, 1, 242, 21, NULL, 'Desenberg', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
(822, 1, 242, 21, NULL, 'Ossendorf', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
(823, 1, 242, 21, NULL, 'Warburg', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
