(825, 1, 242, 21, NULL, 'West Uffelen', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
(826, 1, 242, 21, NULL, 'Meinbitz', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
(827, 1, 242, 21, NULL, 'Kalken', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
(828, 1, 242, 21, NULL, 'Cassel', 1, '2026-05-13 10:23:04', '2026-05-13 10:23:04', 'Omeka\\Entity\\Item'),
(829, 1, 288, 19, NULL, 'Ten vollen overtuigd dat beloften schulden maken vat ik reeds de derde dag na ons vertrek uit Groningen de pen op om u het verslag van onze reis herwaarts mede te deelen...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(830, 1, 288, 19, NULL, '...en om u over de zeden, gebruiken en gewoonten van Duitslands inwooneren te onderhouden, daartoe heb ik noch tyd noch lust...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(831, 1, 288, 19, NULL, 'Wy verlieten dan op Zaturdag de 29 Juny 1816 onder ons vieren onze geboortestad met onze 3 Hollandsche reisgenoten een logement in Munster bepaald hebbende om elkanderen te ontmoeten: in plaats van den gewonen weg naar Coevorden te nemen besloten wy over Eext, Gieten, Gasselte en zoo vervolgens te ryden: zonder eenige byzonderheid passeerden wy successivelyk Haren, Harender-molen, Noord- Mid- en Zuidlaren, hielden ons een oogenblik te Anlo op en lieten van Eext het rytuig ledig naar Gieten ryden intusschen wandelden wy derwaarts langs de beroemde Eexter grafkelder...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(832, 1, 288, 19, NULL, 'Na te Gieten in den herberg by den Scholters Braams eenige ververschingen genomen te hebben, reden wy om 2 uur van daar en kwamen, na Gasselte & Drouen gepasseerd te zyn, te Borger aan, alwaar wy een boterham met slegte koffy gebruikten: van hier is de weg zeer vervelend daar men tot Odoorn eene uitgestrekte heide heeft uitmakende een gedeelte van het bekende Ellersveld...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(833, 1, 288, 19, NULL, '...wy hielden ons niet op te Odoorn, maar dronken te Emmen een kopje thee by den student Amshoff zoon van den Predicant...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(834, 1, 288, 19, NULL, 'Even achter het gehucht Erme hadden wy het ongeluk dat ons de knuppel van de wagen brak...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(835, 1, 288, 19, NULL, '...doch dit had ons zoo lang opgehouden, dat wy na het aanzienlyke Dorp Dalen, dat voorleden jaar geheel verbrand is, gepasseerd te zyn laat en wel in donkeren, in Coevoorden aankwamen alwaar wy by den Hr Pothoff op een delicieus souper gewagt wierden en ons nachtverblyf in de Koppelpaarden namen.', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(836, 1, 288, 19, NULL, '\'s Anderendaags waren wy, om ons in alles maar aan onze volgende levenswyze te gewennen, reeds vroeg opgestaan en na ontbeten Coevorden in alle rigtingen doorkruist en de wallen rondgewandelt te hebben, vertrokken wy van daar voort na vyf uren: wy hadden eenen zeer goeden voerman voor 9 guldens tot Noordhoorn aangenomen deeze reed uitmuntend zoodat wy al ras aan de grenzen van ons Vaderland waren gekomen...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(837, 1, 288, 19, NULL, 'Tot Emmelenkamp ook Emmelicheim genoemd ontmoette ons niets byzonders: wy hielden ons ook slechts een oogenblik aldaar op ten einde tol te betalen hetgeen ons door een bord voor het tolhuis geplaatst, waarop de cyfers van Georgius Rex, wierd aangeduid.', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(838, 1, 288, 19, NULL, 'wy hadden plan om van hier over Nieuhuis en Noordhoorn naar Bentheim te vertrekken, doch de zeer koddige kastelein... verwittigde ons dat wy de Vecht, die wegens de menigvuldige regens zeer gezwollen was, niet konden doorryden \'t welk ons deed besluiten om over Ringe en Velthuis te ryden.', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(839, 1, 288, 19, NULL, 'In laatst genoemde plaats kwamen wy om 10 uur aan en woonden voor een oogenblik de godsdienstoefening by onder het gehoor van Do Koppelman... gelukkig kwamen wy toch het klooster Frenswegen regts latende liggen om 12 uur te Noordhoorn.', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(840, 1, 288, 19, NULL, 'Wy stapten af by de ouders van den Student Sluiter wier overgroote vriendschap wy niet genoeg kunnen roemen: van onze komst verwittigd wierden wy aldaar op een delicieus diner onthaald...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(841, 1, 288, 19, NULL, 'Na afscheid van onze gulle gastheeren genomen te hebben, verlieten wy om 4 uuren Noordhoorn, wy waren tot Bentheim geaccordeerd voor 4-10-\" en weldra door Brandlicht op de Ysterberg gekomen te zynde wierden wy door het hooggelegene kasteel van Bentheim verrast schoon het nog een eind weg ervan af ligt...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(842, 1, 288, 19, NULL, 'Even voor Bentheim lieten wy de wagen naar de herberg ryden & wandelden langs eene zeer moerassige laan naar de Zwavelbron genoegzaam midden in het bosch gelegen: wy vonden het koepeltje, dat op dezelve staat, gesloten...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(843, 1, 288, 19, NULL, 'van hier wandelden wy naar de stad en namen onzen intrek in het witte paard aan de voet van het kasteel gelegen.', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(844, 1, 288, 19, NULL, '...dien wy tegen de volgende dag voor 5 guld tot Steinfurt aannamen...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(845, 1, 288, 19, NULL, 'Het kasteel bezigtigden wy slechts gedeeltelyk van binnen en om de bouwvalligheid van zommige delen, en wyl er weinig byzonders in het overige is...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(846, 1, 288, 19, NULL, 'op de eene zyde van het kasteel staat een toren welke door de Fransche Generaal van Damme by het verlaten van het kasteel geheel met kruid was gevuld geworden... waarna alle inwoners van Bentheim, die gevlugt waren, terugkwamen: aan de tegenovergestelde zyde is het grote stuk rots, Duivels oorkussen genoemd...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(847, 1, 288, 19, NULL, '...na nog eene naburige steengroef, waarby die Heer ons de geheele bewerking toonde, gezien te hebben namen wy afscheid van zyn Ed alsmede van de Hr Goldsmit en begaven ons naar ons logement.', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(848, 1, 288, 19, NULL, '...toen men ons kwam wekken en wy de reis verder naar Steinfort aannamen.', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(849, 1, 288, 19, NULL, 'Het equipagie waarmede wy het bekoorlyk geleegene Bentheim verlieten was juist niet van het brillianste...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(850, 1, 288, 19, NULL, 'Op de zeer vervelende weg ontmoette ons niets byzonders dan dat wy in een huttje onder Wilberg een weinig rechts van de weg afliggende een vrouwtje zagen...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(851, 1, 288, 19, NULL, 'Het kabinet van de Graaf van Steinfurt vonden wy nog even als de Heere reizigers bovengemeld op bl 57&58 van het eerste deel schreven...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(852, 1, 288, 19, NULL, 'van hier wandelden wy gezamentlyk naar het Bagno zynde een lustplaats van den Graaf die thans te Parys is: hetzelve is op een vierde uur van de stad gelegen...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(853, 1, 288, 19, NULL, '...wy wandelden hier vry wat rond en kwamen nog juist bytyds in de stad terug om in de Zon à table d\'hote te eeten.', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(854, 1, 288, 19, NULL, 'Hierdoor zeer versterkt vertrokken wy om twee uur met eenen voor 9 guldens afgehuurde wagen naar Munster: de weg derwaarts is alles behalven aangenaam zynde zeer vevelend en gedeeltelyk in eene regte lyn bylangs de vaart lopende...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(855, 1, 288, 19, NULL, '...het was reeds over acht uuren toen wy deeze oude bisschoplyke stad binnenreden...', 1, '2026-05-13 10:23:42', '2026-05-13 10:23:42', 'Omeka\\Entity\\Item'),
(856, 1, 288, 19, NULL, 'In het logement de stad Amsterdam, waar wy afgestapt zyn, spreekt men reeds niets als Duitsch daar de kastelein in Steinfurt, alwaar wy ons eerste Duitsche geld ontfingen, beide talen sprak...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(857, 1, 288, 19, NULL, '...adresseerde wy ons; na lang te vergeefsch in boekwinkels enz gezogt te hebben, aan eenige Professoren in het voormalige Jesuiten klooster (thans het Universiteits gebouw) vergaderd ten einde een ordo lectionum te bekomen.', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(858, 1, 288, 19, NULL, '...in eene volgende, waarschynlyk in t Paderborn, hoop ik u eenige merkwaardigheden van Munster, die wy morgen zullen opnemen, te beschryven.', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(859, 1, 288, 19, NULL, 'Slechts ééne dag in Munster vertoevende is het geen wonder dat wy dien ook goed gebruikten en reeds vroeg op de been waren om het een en ander te bezigtigen: wy maakten een aanvang met het klooster der barmhartige broeders te bezien...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(860, 1, 288, 19, NULL, 'De kerk tot dit gebouw behorende is zeer fraay en eenigsints naar de St Pieterskerk gebouwd ook vond men er eene Kapel juist naar de Sancta Casa van Loretta gebouwd...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(861, 1, 288, 19, NULL, 'De groote Domkerk juist open ziende staan traden wy dezelve binnen...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(862, 1, 288, 19, NULL, '...hetgeen in dezelve voornaamlyk onze aandagt tot zich trok was de kapel waarin Barentje van Galen... begraven ligt...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(863, 1, 288, 19, NULL, '...zoo zagen wy toch in de capel, naast die van Barentje van Galen, een groote glazen kast waarin te voren een zwaar zilveren oorlogschip... was volgens zommigen door de Staten van Holland volgens anderen door de Blokzylsters aan voornoemde Bisschop gegeven...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(864, 1, 288, 19, NULL, 'Behalven den Dom zagen wy nog de Uberwasser & Lamberti kerken...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(865, 1, 288, 19, NULL, '...aan de toren van de laatste ziet men de 3 yzeren kooyen hangen waarin Jan van Leiden met 2 van zyne voornaamste aanhangers is opgesloten geweest, terwyl aan ieder der 4 pylaren die voor het Stadshuis staan, eene knyptang hangt...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(866, 1, 288, 19, NULL, 'Dit stadhuis uitwendig van geene de minste byzonderheid had echter voor ons Hollanders iets zeer merkwaardigs men vind namelyk in het zelve de zaal waar in 1648 de beroemde Munstersche vrede is getekend geworden...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(867, 1, 288, 19, NULL, 'Door een zoort van gangetje bezyden het Stadhuis over een plaatsje gaande komt men in de bewuste zaal...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(868, 1, 288, 19, NULL, 'Het slot weleer door de bisschoppen, thans door de Commandant der stad bewoond, is wel der moeite waardig om te zien...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(869, 1, 288, 19, NULL, '...de slossverwalter althans sloeg ons verzoek glad af: hier echter niet meede te vrede gingen wy... de schildwagter voorby het slot binnen, door het schoone vestibule, de heerlyke trap op & kwamen zo geheel ongemerkt op de magnifique geheel vergulde & met grote spiegels verzierde zaal...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(870, 1, 288, 19, NULL, 'Toen wy weder beneden kwamen zagen wy de talryke bezetting, die inmiddels op het groote plein voor het slot was te zamen gekomen...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(871, 1, 288, 19, NULL, 'Wy bragten het overige van den avond in de schoone tuin, agter het slot gelegen, door...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(872, 1, 288, 19, NULL, 'Dien zelfden avond arriveerden van Arnhem onze overige Reisgenoten te weten Profr Tydeman van Leiden... die ons slechts tot Gottingen zal vergezellen, terwyl onze andere compagnon de Student Hogendorp reeds vooruitgereist is, welken wy voor Cassel waarschynlyk niet zullen ontmoeten.', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(873, 1, 288, 19, NULL, 'Zie daar dan het een en ander nopens Munster... doch veronderstellende dat gy ook nieuwsgierig zult zyn hoe wy hier te Paderborn zyn gekomen zal ik deeze nog vervolgen tot onze komst alhier.', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(874, 1, 288, 19, NULL, 'Den 3 July. Reeds vroeg vertrokken wy van Munster met de gewoone postwagen...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(875, 1, 288, 19, NULL, '...dat wy om te Paderborn te komen nog menig uur ons zouden moeten vervelen daar de weg tusschen deese plaats en Munster ver van aangenaam doch daaren tegen zeer eentonig is...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(876, 1, 288, 19, NULL, 'Even voor het stadje Telgt, 3 uren van Munster gelegen, ontmoette ons de andere postwagen...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(877, 1, 288, 19, NULL, 'Te Telgt wierden de paarden gevoederd van welk oogenblik wy gebruik stamakten om het wonder doend Mariabeeld, dat daar is, te bezigtigen.', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(878, 1, 288, 19, NULL, 'Dit beeld, dat... uit eene groote lindeboom, voor de poort der stad staande, als eene jonge maagd is uitgegroeid...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(879, 1, 288, 19, NULL, 'In de capel vonden wy het beeld zelve niet maar wel eene menigte groote en kleine krukkenstokjes enz... even als in de kerk daar digt by staande waar wy het beeld vonden...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(880, 1, 288, 19, NULL, '...dat de dief, een Hessisch soldaat en vader van 10 kinderen, gevat zynde voogewend dat de moeder Gods hem gewenkt had...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(881, 1, 288, 19, NULL, 'Telgt verlatende kwamen wy langs eene allervervelendste weg om één uur te Wahrensdorf de eerste station aan, een geruime tyd in Gezelschap gereden te hebbende met eenige wagens gekwetsten en verminkte Pruissen, die nu eerst uit de hospitalen van Holland & Braband... terug kwamen...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(882, 1, 288, 19, NULL, 'In den Koning van Engeland gebruikten wy hier een ellendig... diner...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(883, 1, 288, 19, NULL, '...kwamen wy om 6½ uur, na Beele gepasseerd te zyn, te Clarholtz aan...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(884, 1, 288, 19, NULL, '...zo ik my niet bedrieg was het de dag van de tweede inneming van Parys.', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(885, 1, 288, 19, NULL, 'Het Klooster dat men hier vind zagen wy slechts uitwendig doch gingen even in de vry nette Kerk...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(886, 1, 288, 19, NULL, 'Kort daarna te Herzebrock aankomende hadden wy moeite om een verdekte wagen te bekomen...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(887, 1, 288, 19, NULL, '...kwamen we een paar uur eerder, en wel des nagts om één uur, te Neuenkirchen aan zynde de derde station: hier hadden wy eene zonderlinge ontmoeting...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(888, 1, 288, 19, NULL, '...vonden dat wy in eene stal waren gereden...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(889, 1, 288, 19, NULL, '...belandde na veel horten en botzen eindelyk in een groot vertrek hetwelk door het kleine lampje slechts gedeeltelyk verlicht was...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(890, 1, 288, 19, NULL, '...opende wel verscheiden deuren doch kwam nu eens in eene donkere zykamer, dan eens met de neus in eene kleer of provisie Kast dan weder elders tot het hem eindelyk gelukte het bed van den Postmeester & zijne Ega te vinden...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(891, 1, 288, 19, NULL, '...gaf ons ander licht en bezorgde in een kleinder vertrekje boter, brood en zoogenaamde fusel...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(892, 1, 288, 19, NULL, 'Met dit ellendig rytuig verlieten wy dezen morgen voort na drie uur Neuenkirchen en onophoudelyk stappende besloten wy met iemand, die de weg wist, vooruit te wandelen waardoor wy tydig genoeg op het Hauf, zynde de eerste herberg, aankwamen...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(893, 1, 288, 19, NULL, 'Toen gingen wy weder op ons ellendig rytuig waarmede wy te 10¼ uur te Neuhaus arriveerden, welk stadje tusschen de bergen in een valley liggende zich allerbekoorlykst voordoet...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(894, 1, 288, 19, NULL, '...voorby het voormalige Bisschoplyke Kasteel, dat er uitwendig goed uit ziet, tot wy de andere poort weder uit waren...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(895, 1, 288, 19, NULL, '...door eene schoone laan van castanje boomen rydende kwamen wy ongeveer drie vierde uur daarna & wel om 11 uur hier aan, aan het zeer goede posthuis afstappende.', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(896, 1, 288, 19, NULL, 'Even als te Neuhaus zyn ook hier te Paderborn de straten geheel met mest, modder en slyk opgehoopt...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(897, 1, 288, 19, NULL, 'De stad is de oorsprong van haren naam verschuldigd aan de kleine rivier de Pader, welke door het tezamen vloeyen van 3 onderscheiden beekjes, die uit eenen in de nabyheid gelegende berg ontspringen, in deze stad ontstaat en vervolgens zich in de Lippe ontlast.', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(898, 1, 288, 19, NULL, 'Onder het merkwaardige dat deeze stad oplevert verdient voorzeker de trotsche domkerk genoemd te worden...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(899, 1, 288, 19, NULL, '...wy zagen het monument nog midden in de kerk opgerigt...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(900, 1, 288, 19, NULL, '...trof ons zeer een schoon stuk in marmer verbeeldende het laatste oordeel... zyne fraaye tombe daar juist over, die van bisschop Wilhelm Antoon...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(901, 1, 288, 19, NULL, 'By deeze kerk is het opmerkingswaardig dat men onder het koor van de tegenwoordige nog de oude kerk vindt...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(902, 1, 288, 19, NULL, 'Ook de Jesuitenkerk moet een zeer fraay en bezienswaardig gebouw zyn...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(903, 1, 288, 19, NULL, '...hopende op deze wyze nog heden avond in Cassel te zyn hetgeen men ons hier verzekerd dat geschieden kan, dan Vriend lief ik geloof niet dat wy heden Cassel zullen zien...', 1, '2026-05-13 10:23:43', '2026-05-13 10:23:43', 'Omeka\\Entity\\Item'),
(904, 1, 236, 14, NULL, 'Professor Tydeman', 1, '2026-05-13 10:24:41', '2026-06-30 15:51:30', 'Omeka\\Entity\\Item'),
(905, 1, 236, 14, NULL, 'Student Bodel', 1, '2026-05-13 10:24:41', '2026-05-13 10:24:41', 'Omeka\\Entity\\Item'),
(906, 1, 236, 14, NULL, 'De heer De Geer', 1, '2026-05-13 10:24:41', '2026-05-13 10:24:41', 'Omeka\\Entity\\Item'),
(907, 1, 236, 14, NULL, 'Student Hogendorp', 1, '2026-05-13 10:24:41', '2026-05-13 10:24:41', 'Omeka\\Entity\\Item'),
(908, 1, 288, 17, NULL, 'Sentence where ExampleName is mentioned for this travel', 1, '2026-05-13 10:25:19', '2026-05-13 10:25:19', 'Omeka\\Entity\\Item'),
(909, 1, 288, 17, NULL, 'Dien zelfden avond arriveerden van Arnhem onze overige Reisgenoten te weten Profr Tydeman van Leiden...', 1, '2026-05-13 10:25:19', '2026-05-13 10:25:19', 'Omeka\\Entity\\Item'),
(910, 1, 288, 17, NULL, '...de Stud: Bodel & de Hr de Geer Secretaris van Z.E. de Hr Repelaar van Driel...', 1, '2026-05-13 10:25:19', '2026-05-13 10:25:19', 'Omeka\\Entity\\Item'),
(911, 1, 288, 17, NULL, '...de Hr de Geer Secretaris van Z.E. de Hr Repelaar van Driel die ons slechts tot Gottingen zal vergezellen...', 1, '2026-05-13 10:25:19', '2026-05-13 10:25:19', 'Omeka\\Entity\\Item'),
(912, 1, 288, 17, NULL, '...terwyl onze andere compagnon de Student Hogendorp reeds vooruitgereist is, welken wy voor Cassel waarschynlyk niet zullen ontmoeten.', 1, '2026-05-13 10:25:19', '2026-05-13 10:25:19', 'Omeka\\Entity\\Item'),
