(938, 1, 215, 18, NULL, 'Roomsche kerk Cassel', 1, '2026-05-13 10:26:16', '2026-05-13 10:26:16', 'Omeka\\Entity\\Item'),
(939, 1, 288, 18, NULL, '...intusschen wandelden wy derwaarts langs de beroemde Eexter grafkelder, door van Lier en zyne oudheidkundige brieven over Drente zoo naauwkeurig beschreven...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(940, 1, 288, 18, NULL, '...naar het groote Hunnebed en de 2 drooge en natte kommen over al hetwelk gy de reis door Duitschland van Profr van Swinderen enz op bladz. 14 en 15 van het eerste deel kunt nazien.', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(941, 1, 288, 18, NULL, 'Even voor Bentheim lieten wy de wagen naar de herberg ryden & wandelden langs eene zeer moerassige laan naar de Zwavelbron genoegzaam midden in het bosch gelegen...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(942, 1, 288, 18, NULL, '...wierden wy door het hooggelegene kasteel van Bentheim verrast schoon het nog een eind weg ervan af ligt...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(943, 1, 288, 18, NULL, 'Het kasteel bezigtigden wy slechts gedeeltelyk van binnen en om de bouwvalligheid van zommige delen, en wyl er weinig byzonders in het overige is...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(944, 1, 288, 18, NULL, '...aan de tegenovergestelde zyde is het grote stuk rots, Duivels oorkussen genoemd, waarop in vry duidelyke letters de woorden staan Hic Drusus dixit jura Tubantibus.', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(945, 1, 288, 18, NULL, 'Het kabinet van de Graaf van Steinfurt vonden wy nog even als de Heere reizigers bovengemeld op bl 57&58 van het eerste deel schreven het is volstrekt een rommel zoo van alles door elkander waar ik behalve 3 a 4 goede schilderyen niets byzonders vond.', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(946, 1, 288, 18, NULL, 'van hier wandelden wy gezamentlyk naar het Bagno zynde een lustplaats van den Graaf die thans te Parys is...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(947, 1, 288, 18, NULL, 'voorts vindt men hier nog een colossaal geheel op zich zelf staand waterrad van 102 voet diameter hetwelk het water op eenen toren brengt waardoor eene fontein ter hoogte van 80 voet met eene straal van 13 duim springt...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(948, 1, 288, 18, NULL, 'wy maakten een aanvang met het klooster der barmhartige broeders te bezien welk gesticht zyn oorsprong aan Clemens August verschuldigt is...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(949, 1, 288, 18, NULL, 'De groote Domkerk juist open ziende staan traden wy dezelve binnen: het is een schoon gebouw waar van veele sieraden van beeldhouwwerk enz zyn aangebragt...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(950, 1, 288, 18, NULL, '...hetgeen in dezelve voornaamlyk onze aandagt tot zich trok was de kapel waarin Barentje van Galen, heerschzuchtiger gedachtenis, begraven ligt waar altyd eene brandende lamp hangt; dezelve is door een zwaar metalen hek... van de kerk zelve afgescheiden, hy rust onder eene fraaye graftombe van zwart marmer waarop hy ook is afgebeeld...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(951, 1, 288, 18, NULL, '...verder vind men er nog eene schoone tombe van den Grave van Plettenberg, een zeer schoon & groot altaar & eenige restes van voormalige kostbaarheden.', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(952, 1, 288, 18, NULL, 'Behalven den Dom zagen wy nog de Uberwasser & Lamberti kerken...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(953, 1, 288, 18, NULL, 'Behalven den Dom zagen wy nog de Uberwasser & Lamberti kerken...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(954, 1, 288, 18, NULL, '...en aan de toren van de laatste ziet men de 3 yzeren kooyen hangen waarin Jan van Leiden met 2 van zyne voornaamste aanhangers is opgesloten geweest...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(955, 1, 288, 18, NULL, '...terwyl aan ieder der 4 pylaren die voor het Stadshuis staan, eene knyptang hangt waarmede hun op den 23 January 1536 het vleesch uit het lichaam is gereten daar zy geheel gloeiend waren.', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(956, 1, 288, 18, NULL, 'Dit stadhuis uitwendig van geene de minste byzonderheid had echter voor ons Hollanders iets zeer merkwaardigs...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(957, 1, 288, 18, NULL, '...men vind namelyk in het zelve de zaal waar in 1648 de beroemde Munstersche vrede is getekend geworden & die juist zoo gebleven is als zy by het vertrek der gezanten was...', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
(958, 1, 288, 18, NULL, 'Te Telgt wierden de paarden gevoederd van welk oogenblik wy gebruik maakten om het wonder doend Mariabeeld, dat daar is, te bezigtigen.', 1, '2026-05-13 10:27:07', '2026-05-13 10:27:07', 'Omeka\\Entity\\Item'),
