(2869, 828, 10, NULL, 'literal', NULL, NULL, 'LOC047', NULL, 1),
(2870, 828, 40, NULL, 'literal', NULL, NULL, '51.3127, 9.4797', NULL, 1),
(2871, 829, 1, NULL, 'literal', NULL, NULL, 'Ten vollen overtuigd dat beloften schulden maken vat ik reeds de derde dag na ons vertrek uit Groningen de pen op om u het verslag van onze reis herwaarts mede te deelen...', NULL, 1),
(2872, 829, 10, NULL, 'literal', NULL, NULL, 'PHRLOC001', NULL, 1),
(2873, 829, 812, 782, 'resource', NULL, NULL, NULL, NULL, 1),
(2874, 830, 1, NULL, 'literal', NULL, NULL, '...en om u over de zeden, gebruiken en gewoonten van Duitslands inwooneren te onderhouden, daartoe heb ik noch tyd noch lust...', NULL, 1),
(2875, 830, 10, NULL, 'literal', NULL, NULL, 'PHRLOC002', NULL, 1),
(2876, 830, 812, 782, 'resource', NULL, NULL, NULL, NULL, 1),
(2877, 831, 1, NULL, 'literal', NULL, NULL, 'Wy verlieten dan op Zaturdag de 29 Juny 1816 onder ons vieren onze geboortestad met onze 3 Hollandsche reisgenoten een logement in Munster bepaald hebbende om elkanderen te ontmoeten: in plaats van den gewonen weg naar Coevorden te nemen besloten wy over Eext, Gieten, Gasselte en zoo vervolgens te ryden: zonder eenige byzonderheid passeerden wy successivelyk Haren, Harender-molen, Noord- Mid- en Zuidlaren, hielden ons een oogenblik te Anlo op en lieten van Eext het rytuig ledig naar Gieten ryden intusschen wandelden wy derwaarts langs de beroemde Eexter grafkelder...', NULL, 1),
(2878, 831, 10, NULL, 'literal', NULL, NULL, 'PHRLOC003', NULL, 1),
(2879, 831, 812, 782, 'resource', NULL, NULL, NULL, NULL, 1),
(2880, 831, 812, 783, 'resource', NULL, NULL, NULL, NULL, 1),
(2881, 831, 812, 784, 'resource', NULL, NULL, NULL, NULL, 1),
(2882, 831, 812, 785, 'resource', NULL, NULL, NULL, NULL, 1),
(2883, 831, 812, 786, 'resource', NULL, NULL, NULL, NULL, 1),
(2884, 831, 812, 787, 'resource', NULL, NULL, NULL, NULL, 1),
(2885, 831, 812, 788, 'resource', NULL, NULL, NULL, NULL, 1),
(2886, 831, 812, 789, 'resource', NULL, NULL, NULL, NULL, 1),
(2887, 831, 812, 790, 'resource', NULL, NULL, NULL, NULL, 1),
(2888, 831, 812, 791, 'resource', NULL, NULL, NULL, NULL, 1),
(2889, 831, 812, 797, 'resource', NULL, NULL, NULL, NULL, 1),
(2890, 831, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(2891, 832, 1, NULL, 'literal', NULL, NULL, 'Na te Gieten in den herberg by den Scholters Braams eenige ververschingen genomen te hebben, reden wy om 2 uur van daar en kwamen, na Gasselte & Drouen gepasseerd te zyn, te Borger aan, alwaar wy een boterham met slegte koffy gebruikten: van hier is de weg zeer vervelend daar men tot Odoorn eene uitgestrekte heide heeft uitmakende een gedeelte van het bekende Ellersveld...', NULL, 1),
(2892, 832, 10, NULL, 'literal', NULL, NULL, 'PHRLOC004', NULL, 1),
(2893, 832, 812, 790, 'resource', NULL, NULL, NULL, NULL, 1),
(2894, 832, 812, 791, 'resource', NULL, NULL, NULL, NULL, 1),
(2895, 832, 812, 792, 'resource', NULL, NULL, NULL, NULL, 1),
(2896, 832, 812, 793, 'resource', NULL, NULL, NULL, NULL, 1),
(2897, 832, 812, 794, 'resource', NULL, NULL, NULL, NULL, 1),
(2898, 833, 1, NULL, 'literal', NULL, NULL, '...wy hielden ons niet op te Odoorn, maar dronken te Emmen een kopje thee by den student Amshoff zoon van den Predicant...', NULL, 1),
(2899, 833, 10, NULL, 'literal', NULL, NULL, 'PHRLOC005', NULL, 1),
(2900, 833, 812, 794, 'resource', NULL, NULL, NULL, NULL, 1),
(2901, 833, 812, 795, 'resource', NULL, NULL, NULL, NULL, 1),
(2902, 834, 1, NULL, 'literal', NULL, NULL, 'Even achter het gehucht Erme hadden wy het ongeluk dat ons de knuppel van de wagen brak...', NULL, 1),
(2903, 834, 10, NULL, 'literal', NULL, NULL, 'PHRLOC006', NULL, 1),
(2904, 834, 812, 795, 'resource', NULL, NULL, NULL, NULL, 1),
(2905, 834, 812, 796, 'resource', NULL, NULL, NULL, NULL, 1),
(2906, 835, 1, NULL, 'literal', NULL, NULL, '...doch dit had ons zoo lang opgehouden, dat wy na het aanzienlyke Dorp Dalen, dat voorleden jaar geheel verbrand is, gepasseerd te zyn laat en wel in donkeren, in Coevoorden aankwamen alwaar wy by den Hr Pothoff op een delicieus souper gewagt wierden en ons nachtverblyf in de Koppelpaarden namen.', NULL, 1),
(2907, 835, 10, NULL, 'literal', NULL, NULL, 'PHRLOC007', NULL, 1),
(2908, 835, 812, 796, 'resource', NULL, NULL, NULL, NULL, 1),
(2909, 835, 812, 797, 'resource', NULL, NULL, NULL, NULL, 1),
(2910, 836, 1, NULL, 'literal', NULL, NULL, '\'s Anderendaags waren wy, om ons in alles maar aan onze volgende levenswyze te gewennen, reeds vroeg opgestaan en na ontbeten Coevorden in alle rigtingen doorkruist en de wallen rondgewandelt te hebben, vertrokken wy van daar voort na vyf uren: wy hadden eenen zeer goeden voerman voor 9 guldens tot Noordhoorn aangenomen deeze reed uitmuntend zoodat wy al ras aan de grenzen van ons Vaderland waren gekomen...', NULL, 1),
(2911, 836, 10, NULL, 'literal', NULL, NULL, 'PHRLOC008', NULL, 1),
(2912, 836, 812, 797, 'resource', NULL, NULL, NULL, NULL, 1),
(2913, 836, 812, 802, 'resource', NULL, NULL, NULL, NULL, 1),
(2914, 837, 1, NULL, 'literal', NULL, NULL, 'Tot Emmelenkamp ook Emmelicheim genoemd ontmoette ons niets byzonders: wy hielden ons ook slechts een oogenblik aldaar op ten einde tol te betalen hetgeen ons door een bord voor het tolhuis geplaatst, waarop de cyfers van Georgius Rex, wierd aangeduid.', NULL, 1),
(2915, 837, 10, NULL, 'literal', NULL, NULL, 'PHRLOC009', NULL, 1),
(2916, 837, 812, 798, 'resource', NULL, NULL, NULL, NULL, 1),
(2917, 838, 1, NULL, 'literal', NULL, NULL, 'wy hadden plan om van hier over Nieuhuis en Noordhoorn naar Bentheim te vertrekken, doch de zeer koddige kastelein... verwittigde ons dat wy de Vecht, die wegens de menigvuldige regens zeer gezwollen was, niet konden doorryden \'t welk ons deed besluiten om over Ringe en Velthuis te ryden.', NULL, 1),
(2918, 838, 10, NULL, 'literal', NULL, NULL, 'PHRLOC010', NULL, 1),
(2919, 838, 812, 799, 'resource', NULL, NULL, NULL, NULL, 1),
(2920, 838, 812, 800, 'resource', NULL, NULL, NULL, NULL, 1),
(2921, 838, 812, 802, 'resource', NULL, NULL, NULL, NULL, 1),
(2922, 838, 812, 804, 'resource', NULL, NULL, NULL, NULL, 1),
(2923, 839, 1, NULL, 'literal', NULL, NULL, 'In laatst genoemde plaats kwamen wy om 10 uur aan en woonden voor een oogenblik de godsdienstoefening by onder het gehoor van Do Koppelman... gelukkig kwamen wy toch het klooster Frenswegen regts latende liggen om 12 uur te Noordhoorn.', NULL, 1),
(2924, 839, 10, NULL, 'literal', NULL, NULL, 'PHRLOC011', NULL, 1),
(2925, 839, 812, 800, 'resource', NULL, NULL, NULL, NULL, 1),
(2926, 839, 812, 801, 'resource', NULL, NULL, NULL, NULL, 1),
(2927, 839, 812, 802, 'resource', NULL, NULL, NULL, NULL, 1),
(2928, 840, 1, NULL, 'literal', NULL, NULL, 'Wy stapten af by de ouders van den Student Sluiter wier overgroote vriendschap wy niet genoeg kunnen roemen: van onze komst verwittigd wierden wy aldaar op een delicieus diner onthaald...', NULL, 1),
(2929, 840, 10, NULL, 'literal', NULL, NULL, 'PHRLOC012', NULL, 1),
(2930, 840, 812, 802, 'resource', NULL, NULL, NULL, NULL, 1),
(2931, 841, 1, NULL, 'literal', NULL, NULL, 'Na afscheid van onze gulle gastheeren genomen te hebben, verlieten wy om 4 uuren Noordhoorn, wy waren tot Bentheim geaccordeerd voor 4-10-\" en weldra door Brandlicht op de Ysterberg gekomen te zynde wierden wy door het hooggelegene kasteel van Bentheim verrast schoon het nog een eind weg ervan af ligt...', NULL, 1),
(2932, 841, 10, NULL, 'literal', NULL, NULL, 'PHRLOC013', NULL, 1),
(2933, 841, 812, 802, 'resource', NULL, NULL, NULL, NULL, 1),
(2934, 841, 812, 803, 'resource', NULL, NULL, NULL, NULL, 1),
(2935, 841, 812, 804, 'resource', NULL, NULL, NULL, NULL, 1),
(2936, 842, 1, NULL, 'literal', NULL, NULL, 'Even voor Bentheim lieten wy de wagen naar de herberg ryden & wandelden langs eene zeer moerassige laan naar de Zwavelbron genoegzaam midden in het bosch gelegen: wy vonden het koepeltje, dat op dezelve staat, gesloten...', NULL, 1),
(2937, 842, 10, NULL, 'literal', NULL, NULL, 'PHRLOC014', NULL, 1),
(2938, 842, 812, 804, 'resource', NULL, NULL, NULL, NULL, 1),
(2939, 843, 1, NULL, 'literal', NULL, NULL, 'van hier wandelden wy naar de stad en namen onzen intrek in het witte paard aan de voet van het kasteel gelegen.', NULL, 1),
(2940, 843, 10, NULL, 'literal', NULL, NULL, 'PHRLOC015', NULL, 1),
(2941, 843, 812, 804, 'resource', NULL, NULL, NULL, NULL, 1),
(2942, 844, 1, NULL, 'literal', NULL, NULL, '...dien wy tegen de volgende dag voor 5 guld tot Steinfurt aannamen...', NULL, 1),
(2943, 844, 10, NULL, 'literal', NULL, NULL, 'PHRLOC016', NULL, 1),
(2944, 844, 812, 806, 'resource', NULL, NULL, NULL, NULL, 1),
(2945, 845, 1, NULL, 'literal', NULL, NULL, 'Het kasteel bezigtigden wy slechts gedeeltelyk van binnen en om de bouwvalligheid van zommige delen, en wyl er weinig byzonders in het overige is...', NULL, 1),
(2946, 845, 10, NULL, 'literal', NULL, NULL, 'PHRLOC017', NULL, 1),
(2947, 845, 812, 804, 'resource', NULL, NULL, NULL, NULL, 1),
(2948, 846, 1, NULL, 'literal', NULL, NULL, 'op de eene zyde van het kasteel staat een toren welke door de Fransche Generaal van Damme by het verlaten van het kasteel geheel met kruid was gevuld geworden... waarna alle inwoners van Bentheim, die gevlugt waren, terugkwamen: aan de tegenovergestelde zyde is het grote stuk rots, Duivels oorkussen genoemd...', NULL, 1),
(2949, 846, 10, NULL, 'literal', NULL, NULL, 'PHRLOC018', NULL, 1),
(2950, 846, 812, 804, 'resource', NULL, NULL, NULL, NULL, 1),
(2951, 847, 1, NULL, 'literal', NULL, NULL, '...na nog eene naburige steengroef, waarby die Heer ons de geheele bewerking toonde, gezien te hebben namen wy afscheid van zyn Ed alsmede van de Hr Goldsmit en begaven ons naar ons logement.', NULL, 1),
(2952, 847, 10, NULL, 'literal', NULL, NULL, 'PHRLOC019', NULL, 1),
(2953, 847, 812, 804, 'resource', NULL, NULL, NULL, NULL, 1),
(2954, 848, 1, NULL, 'literal', NULL, NULL, '...toen men ons kwam wekken en wy de reis verder naar Steinfort aannamen.', NULL, 1),
(2955, 848, 10, NULL, 'literal', NULL, NULL, 'PHRLOC020', NULL, 1),
(2956, 848, 812, 806, 'resource', NULL, NULL, NULL, NULL, 1),
(2957, 849, 1, NULL, 'literal', NULL, NULL, 'Het equipagie waarmede wy het bekoorlyk geleegene Bentheim verlieten was juist niet van het brillianste...', NULL, 1),
(2958, 849, 10, NULL, 'literal', NULL, NULL, 'PHRLOC021', NULL, 1),
(2959, 849, 812, 804, 'resource', NULL, NULL, NULL, NULL, 1),
(2960, 850, 1, NULL, 'literal', NULL, NULL, 'Op de zeer vervelende weg ontmoette ons niets byzonders dan dat wy in een huttje onder Wilberg een weinig rechts van de weg afliggende een vrouwtje zagen...', NULL, 1),
(2961, 850, 10, NULL, 'literal', NULL, NULL, 'PHRLOC022', NULL, 1),
(2962, 850, 812, 805, 'resource', NULL, NULL, NULL, NULL, 1),
(2963, 851, 1, NULL, 'literal', NULL, NULL, 'Het kabinet van de Graaf van Steinfurt vonden wy nog even als de Heere reizigers bovengemeld op bl 57&58 van het eerste deel schreven...', NULL, 1),
(2964, 851, 10, NULL, 'literal', NULL, NULL, 'PHRLOC023', NULL, 1),
(2965, 851, 812, 806, 'resource', NULL, NULL, NULL, NULL, 1),
(2966, 852, 1, NULL, 'literal', NULL, NULL, 'van hier wandelden wy gezamentlyk naar het Bagno zynde een lustplaats van den Graaf die thans te Parys is: hetzelve is op een vierde uur van de stad gelegen...', NULL, 1),
(2967, 852, 10, NULL, 'literal', NULL, NULL, 'PHRLOC024', NULL, 1),
(2968, 852, 812, 806, 'resource', NULL, NULL, NULL, NULL, 1),
(2969, 853, 1, NULL, 'literal', NULL, NULL, '...wy wandelden hier vry wat rond en kwamen nog juist bytyds in de stad terug om in de Zon à table d\'hote te eeten.', NULL, 1),
(2970, 853, 10, NULL, 'literal', NULL, NULL, 'PHRLOC025', NULL, 1),
(2971, 853, 812, 806, 'resource', NULL, NULL, NULL, NULL, 1),
(2972, 854, 1, NULL, 'literal', NULL, NULL, 'Hierdoor zeer versterkt vertrokken wy om twee uur met eenen voor 9 guldens afgehuurde wagen naar Munster: de weg derwaarts is alles behalven aangenaam zynde zeer vevelend en gedeeltelyk in eene regte lyn bylangs de vaart lopende...', NULL, 1),
(2973, 854, 10, NULL, 'literal', NULL, NULL, 'PHRLOC026', NULL, 1),
(2974, 854, 812, 806, 'resource', NULL, NULL, NULL, NULL, 1),
(2975, 854, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(2976, 855, 1, NULL, 'literal', NULL, NULL, '...het was reeds over acht uuren toen wy deeze oude bisschoplyke stad binnenreden...', NULL, 1),
(2977, 855, 10, NULL, 'literal', NULL, NULL, 'PHRLOC027', NULL, 1),
(2978, 855, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(2979, 856, 1, NULL, 'literal', NULL, NULL, 'In het logement de stad Amsterdam, waar wy afgestapt zyn, spreekt men reeds niets als Duitsch daar de kastelein in Steinfurt, alwaar wy ons eerste Duitsche geld ontfingen, beide talen sprak...', NULL, 1),
(2980, 856, 10, NULL, 'literal', NULL, NULL, 'PHRLOC028', NULL, 1),
(2981, 856, 812, 806, 'resource', NULL, NULL, NULL, NULL, 1),
(2982, 856, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(2983, 857, 1, NULL, 'literal', NULL, NULL, '...adresseerde wy ons; na lang te vergeefsch in boekwinkels enz gezogt te hebben, aan eenige Professoren in het voormalige Jesuiten klooster (thans het Universiteits gebouw) vergaderd ten einde een ordo lectionum te bekomen.', NULL, 1),
(2984, 857, 10, NULL, 'literal', NULL, NULL, 'PHRLOC029', NULL, 1),
(2985, 857, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(2986, 858, 1, NULL, 'literal', NULL, NULL, '...in eene volgende, waarschynlyk in t Paderborn, hoop ik u eenige merkwaardigheden van Munster, die wy morgen zullen opnemen, te beschryven.', NULL, 1),
(2987, 858, 10, NULL, 'literal', NULL, NULL, 'PHRLOC030', NULL, 1),
(2988, 858, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(2989, 858, 812, 815, 'resource', NULL, NULL, NULL, NULL, 1),
(2990, 859, 1, NULL, 'literal', NULL, NULL, 'Slechts ééne dag in Munster vertoevende is het geen wonder dat wy dien ook goed gebruikten en reeds vroeg op de been waren om het een en ander te bezigtigen: wy maakten een aanvang met het klooster der barmhartige broeders te bezien...', NULL, 1),
(2991, 859, 10, NULL, 'literal', NULL, NULL, 'PHRLOC031', NULL, 1),
(2992, 859, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(2993, 860, 1, NULL, 'literal', NULL, NULL, 'De kerk tot dit gebouw behorende is zeer fraay en eenigsints naar de St Pieterskerk gebouwd ook vond men er eene Kapel juist naar de Sancta Casa van Loretta gebouwd...', NULL, 1),
(2994, 860, 10, NULL, 'literal', NULL, NULL, 'PHRLOC032', NULL, 1),
(2995, 860, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(2996, 861, 1, NULL, 'literal', NULL, NULL, 'De groote Domkerk juist open ziende staan traden wy dezelve binnen...', NULL, 1),
(2997, 861, 10, NULL, 'literal', NULL, NULL, 'PHRLOC033', NULL, 1),
(2998, 861, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(2999, 862, 1, NULL, 'literal', NULL, NULL, '...hetgeen in dezelve voornaamlyk onze aandagt tot zich trok was de kapel waarin Barentje van Galen... begraven ligt...', NULL, 1),
(3000, 862, 10, NULL, 'literal', NULL, NULL, 'PHRLOC034', NULL, 1),
(3001, 862, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3002, 863, 1, NULL, 'literal', NULL, NULL, '...zoo zagen wy toch in de capel, naast die van Barentje van Galen, een groote glazen kast waarin te voren een zwaar zilveren oorlogschip... was volgens zommigen door de Staten van Holland volgens anderen door de Blokzylsters aan voornoemde Bisschop gegeven...', NULL, 1),
(3003, 863, 10, NULL, 'literal', NULL, NULL, 'PHRLOC035', NULL, 1),
(3004, 863, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3005, 864, 1, NULL, 'literal', NULL, NULL, 'Behalven den Dom zagen wy nog de Uberwasser & Lamberti kerken...', NULL, 1),
(3006, 864, 10, NULL, 'literal', NULL, NULL, 'PHRLOC036', NULL, 1),
(3007, 864, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3008, 865, 1, NULL, 'literal', NULL, NULL, '...aan de toren van de laatste ziet men de 3 yzeren kooyen hangen waarin Jan van Leiden met 2 van zyne voornaamste aanhangers is opgesloten geweest, terwyl aan ieder der 4 pylaren die voor het Stadshuis staan, eene knyptang hangt...', NULL, 1),
(3009, 865, 10, NULL, 'literal', NULL, NULL, 'PHRLOC037', NULL, 1),
(3010, 865, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3011, 866, 1, NULL, 'literal', NULL, NULL, 'Dit stadhuis uitwendig van geene de minste byzonderheid had echter voor ons Hollanders iets zeer merkwaardigs men vind namelyk in het zelve de zaal waar in 1648 de beroemde Munstersche vrede is getekend geworden...', NULL, 1),
(3012, 866, 10, NULL, 'literal', NULL, NULL, 'PHRLOC038', NULL, 1),
(3013, 866, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3014, 867, 1, NULL, 'literal', NULL, NULL, 'Door een zoort van gangetje bezyden het Stadhuis over een plaatsje gaande komt men in de bewuste zaal...', NULL, 1),
(3015, 867, 10, NULL, 'literal', NULL, NULL, 'PHRLOC039', NULL, 1),
(3016, 867, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3017, 868, 1, NULL, 'literal', NULL, NULL, 'Het slot weleer door de bisschoppen, thans door de Commandant der stad bewoond, is wel der moeite waardig om te zien...', NULL, 1),
(3018, 868, 10, NULL, 'literal', NULL, NULL, 'PHRLOC040', NULL, 1),
(3019, 868, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3020, 869, 1, NULL, 'literal', NULL, NULL, '...de slossverwalter althans sloeg ons verzoek glad af: hier echter niet meede te vrede gingen wy... de schildwagter voorby het slot binnen, door het schoone vestibule, de heerlyke trap op & kwamen zo geheel ongemerkt op de magnifique geheel vergulde & met grote spiegels verzierde zaal...', NULL, 1),
(3021, 869, 10, NULL, 'literal', NULL, NULL, 'PHRLOC041', NULL, 1),
(3022, 869, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3023, 870, 1, NULL, 'literal', NULL, NULL, 'Toen wy weder beneden kwamen zagen wy de talryke bezetting, die inmiddels op het groote plein voor het slot was te zamen gekomen...', NULL, 1),
(3024, 870, 10, NULL, 'literal', NULL, NULL, 'PHRLOC042', NULL, 1),
(3025, 870, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3026, 871, 1, NULL, 'literal', NULL, NULL, 'Wy bragten het overige van den avond in de schoone tuin, agter het slot gelegen, door...', NULL, 1),
(3027, 871, 10, NULL, 'literal', NULL, NULL, 'PHRLOC043', NULL, 1),
(3028, 871, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3029, 872, 1, NULL, 'literal', NULL, NULL, 'Dien zelfden avond arriveerden van Arnhem onze overige Reisgenoten te weten Profr Tydeman van Leiden... die ons slechts tot Gottingen zal vergezellen, terwyl onze andere compagnon de Student Hogendorp reeds vooruitgereist is, welken wy voor Cassel waarschynlyk niet zullen ontmoeten.', NULL, 1),
(3030, 872, 10, NULL, 'literal', NULL, NULL, 'PHRLOC044', NULL, 1),
(3031, 872, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3032, 873, 1, NULL, 'literal', NULL, NULL, 'Zie daar dan het een en ander nopens Munster... doch veronderstellende dat gy ook nieuwsgierig zult zyn hoe wy hier te Paderborn zyn gekomen zal ik deeze nog vervolgen tot onze komst alhier.', NULL, 1),
(3033, 873, 10, NULL, 'literal', NULL, NULL, 'PHRLOC045', NULL, 1),
(3034, 873, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3035, 873, 812, 815, 'resource', NULL, NULL, NULL, NULL, 1),
(3036, 874, 1, NULL, 'literal', NULL, NULL, 'Den 3 July. Reeds vroeg vertrokken wy van Munster met de gewoone postwagen...', NULL, 1),
(3037, 874, 10, NULL, 'literal', NULL, NULL, 'PHRLOC046', NULL, 1),
(3038, 874, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3039, 875, 1, NULL, 'literal', NULL, NULL, '...dat wy om te Paderborn te komen nog menig uur ons zouden moeten vervelen daar de weg tusschen deese plaats en Munster ver van aangenaam doch daaren tegen zeer eentonig is...', NULL, 1),
(3040, 875, 10, NULL, 'literal', NULL, NULL, 'PHRLOC047', NULL, 1),
(3041, 875, 812, 807, 'resource', NULL, NULL, NULL, NULL, 1),
(3042, 875, 812, 815, 'resource', NULL, NULL, NULL, NULL, 1),
(3043, 876, 1, NULL, 'literal', NULL, NULL, 'Even voor het stadje Telgt, 3 uren van Munster gelegen, ontmoette ons de andere postwagen...', NULL, 1),
(3044, 876, 10, NULL, 'literal', NULL, NULL, 'PHRLOC048', NULL, 1),
(3045, 876, 812, 808, 'resource', NULL, NULL, NULL, NULL, 1),
(3046, 877, 1, NULL, 'literal', NULL, NULL, 'Te Telgt wierden de paarden gevoederd van welk oogenblik wy gebruik stamakten om het wonder doend Mariabeeld, dat daar is, te bezigtigen.', NULL, 1),
(3047, 877, 10, NULL, 'literal', NULL, NULL, 'PHRLOC049', NULL, 1),
(3048, 877, 812, 808, 'resource', NULL, NULL, NULL, NULL, 1),
(3049, 878, 1, NULL, 'literal', NULL, NULL, 'Dit beeld, dat... uit eene groote lindeboom, voor de poort der stad staande, als eene jonge maagd is uitgegroeid...', NULL, 1),
(3050, 878, 10, NULL, 'literal', NULL, NULL, 'PHRLOC050', NULL, 1),
(3051, 878, 812, 808, 'resource', NULL, NULL, NULL, NULL, 1),
(3052, 879, 1, NULL, 'literal', NULL, NULL, 'In de capel vonden wy het beeld zelve niet maar wel eene menigte groote en kleine krukkenstokjes enz... even als in de kerk daar digt by staande waar wy het beeld vonden...', NULL, 1),
(3053, 879, 10, NULL, 'literal', NULL, NULL, 'PHRLOC051', NULL, 1),
(3054, 879, 812, 808, 'resource', NULL, NULL, NULL, NULL, 1),
(3055, 880, 1, NULL, 'literal', NULL, NULL, '...dat de dief, een Hessisch soldaat en vader van 10 kinderen, gevat zynde voogewend dat de moeder Gods hem gewenkt had...', NULL, 1),
(3056, 880, 10, NULL, 'literal', NULL, NULL, 'PHRLOC052', NULL, 1),
(3057, 880, 812, 808, 'resource', NULL, NULL, NULL, NULL, 1),
(3058, 881, 1, NULL, 'literal', NULL, NULL, 'Telgt verlatende kwamen wy langs eene allervervelendste weg om één uur te Wahrensdorf de eerste station aan, een geruime tyd in Gezelschap gereden te hebbende met eenige wagens gekwetsten en verminkte Pruissen, die nu eerst uit de hospitalen van Holland & Braband... terug kwamen...', NULL, 1),
(3059, 881, 10, NULL, 'literal', NULL, NULL, 'PHRLOC053', NULL, 1),
(3060, 881, 812, 808, 'resource', NULL, NULL, NULL, NULL, 1),
(3061, 881, 812, 809, 'resource', NULL, NULL, NULL, NULL, 1),
(3062, 882, 1, NULL, 'literal', NULL, NULL, 'In den Koning van Engeland gebruikten wy hier een ellendig... diner...', NULL, 1),
(3063, 882, 10, NULL, 'literal', NULL, NULL, 'PHRLOC054', NULL, 1),
(3064, 882, 812, 809, 'resource', NULL, NULL, NULL, NULL, 1),
(3065, 883, 1, NULL, 'literal', NULL, NULL, '...kwamen wy om 6½ uur, na Beele gepasseerd te zyn, te Clarholtz aan...', NULL, 1),
(3066, 883, 10, NULL, 'literal', NULL, NULL, 'PHRLOC055', NULL, 1),
(3067, 883, 812, 810, 'resource', NULL, NULL, NULL, NULL, 1),
(3068, 883, 812, 811, 'resource', NULL, NULL, NULL, NULL, 1),
(3069, 884, 1, NULL, 'literal', NULL, NULL, '...zo ik my niet bedrieg was het de dag van de tweede inneming van Parys.', NULL, 1),
(3070, 884, 10, NULL, 'literal', NULL, NULL, 'PHRLOC056', NULL, 1),
(3071, 884, 812, 811, 'resource', NULL, NULL, NULL, NULL, 1),
(3072, 885, 1, NULL, 'literal', NULL, NULL, 'Het Klooster dat men hier vind zagen wy slechts uitwendig doch gingen even in de vry nette Kerk...', NULL, 1),
(3073, 885, 10, NULL, 'literal', NULL, NULL, 'PHRLOC057', NULL, 1),
(3074, 885, 812, 811, 'resource', NULL, NULL, NULL, NULL, 1),
(3075, 886, 1, NULL, 'literal', NULL, NULL, 'Kort daarna te Herzebrock aankomende hadden wy moeite om een verdekte wagen te bekomen...', NULL, 1),
(3076, 886, 10, NULL, 'literal', NULL, NULL, 'PHRLOC058', NULL, 1),
(3077, 886, 812, 812, 'resource', NULL, NULL, NULL, NULL, 1),
(3078, 887, 1, NULL, 'literal', NULL, NULL, '...kwamen we een paar uur eerder, en wel des nagts om één uur, te Neuenkirchen aan zynde de derde station: hier hadden wy eene zonderlinge ontmoeting...', NULL, 1),
(3079, 887, 10, NULL, 'literal', NULL, NULL, 'PHRLOC059', NULL, 1),
(3080, 887, 812, 813, 'resource', NULL, NULL, NULL, NULL, 1),
(3081, 888, 1, NULL, 'literal', NULL, NULL, '...vonden dat wy in eene stal waren gereden...', NULL, 1),
(3082, 888, 10, NULL, 'literal', NULL, NULL, 'PHRLOC060', NULL, 1),
(3083, 888, 812, 813, 'resource', NULL, NULL, NULL, NULL, 1),
(3084, 889, 1, NULL, 'literal', NULL, NULL, '...belandde na veel horten en botzen eindelyk in een groot vertrek hetwelk door het kleine lampje slechts gedeeltelyk verlicht was...', NULL, 1),
(3085, 889, 10, NULL, 'literal', NULL, NULL, 'PHRLOC061', NULL, 1),
(3086, 889, 812, 813, 'resource', NULL, NULL, NULL, NULL, 1),
(3087, 890, 1, NULL, 'literal', NULL, NULL, '...opende wel verscheiden deuren doch kwam nu eens in eene donkere zykamer, dan eens met de neus in eene kleer of provisie Kast dan weder elders tot het hem eindelyk gelukte het bed van den Postmeester & zijne Ega te vinden...', NULL, 1),
(3088, 890, 10, NULL, 'literal', NULL, NULL, 'PHRLOC062', NULL, 1),
(3089, 890, 812, 813, 'resource', NULL, NULL, NULL, NULL, 1),
(3090, 891, 1, NULL, 'literal', NULL, NULL, '...gaf ons ander licht en bezorgde in een kleinder vertrekje boter, brood en zoogenaamde fusel...', NULL, 1),
(3091, 891, 10, NULL, 'literal', NULL, NULL, 'PHRLOC063', NULL, 1),
(3092, 891, 812, 813, 'resource', NULL, NULL, NULL, NULL, 1),
(3093, 892, 1, NULL, 'literal', NULL, NULL, 'Met dit ellendig rytuig verlieten wy dezen morgen voort na drie uur Neuenkirchen en onophoudelyk stappende besloten wy met iemand, die de weg wist, vooruit te wandelen waardoor wy tydig genoeg op het Hauf, zynde de eerste herberg, aankwamen...', NULL, 1),
(3094, 892, 10, NULL, 'literal', NULL, NULL, 'PHRLOC064', NULL, 1),
(3095, 892, 812, 813, 'resource', NULL, NULL, NULL, NULL, 1),
(3096, 893, 1, NULL, 'literal', NULL, NULL, 'Toen gingen wy weder op ons ellendig rytuig waarmede wy te 10¼ uur te Neuhaus arriveerden, welk stadje tusschen de bergen in een valley liggende zich allerbekoorlykst voordoet...', NULL, 1),
(3097, 893, 10, NULL, 'literal', NULL, NULL, 'PHRLOC065', NULL, 1),
(3098, 893, 812, 814, 'resource', NULL, NULL, NULL, NULL, 1),
(3099, 894, 1, NULL, 'literal', NULL, NULL, '...voorby het voormalige Bisschoplyke Kasteel, dat er uitwendig goed uit ziet, tot wy de andere poort weder uit waren...', NULL, 1),
(3100, 894, 10, NULL, 'literal', NULL, NULL, 'PHRLOC066', NULL, 1),
(3101, 894, 812, 814, 'resource', NULL, NULL, NULL, NULL, 1),
(3102, 895, 1, NULL, 'literal', NULL, NULL, '...door eene schoone laan van castanje boomen rydende kwamen wy ongeveer drie vierde uur daarna & wel om 11 uur hier aan, aan het zeer goede posthuis afstappende.', NULL, 1),
(3103, 895, 10, NULL, 'literal', NULL, NULL, 'PHRLOC067', NULL, 1),
(3104, 895, 812, 815, 'resource', NULL, NULL, NULL, NULL, 1),
(3105, 896, 1, NULL, 'literal', NULL, NULL, 'Even als te Neuhaus zyn ook hier te Paderborn de straten geheel met mest, modder en slyk opgehoopt...', NULL, 1),
(3106, 896, 10, NULL, 'literal', NULL, NULL, 'PHRLOC068', NULL, 1),
(3107, 896, 812, 814, 'resource', NULL, NULL, NULL, NULL, 1),
(3108, 896, 812, 815, 'resource', NULL, NULL, NULL, NULL, 1),
(3109, 897, 1, NULL, 'literal', NULL, NULL, 'De stad is de oorsprong van haren naam verschuldigd aan de kleine rivier de Pader, welke door het tezamen vloeyen van 3 onderscheiden beekjes, die uit eenen in de nabyheid gelegende berg ontspringen, in deze stad ontstaat en vervolgens zich in de Lippe ontlast.', NULL, 1),
(3110, 897, 10, NULL, 'literal', NULL, NULL, 'PHRLOC069', NULL, 1),
(3111, 897, 812, 815, 'resource', NULL, NULL, NULL, NULL, 1),
(3112, 898, 1, NULL, 'literal', NULL, NULL, 'Onder het merkwaardige dat deeze stad oplevert verdient voorzeker de trotsche domkerk genoemd te worden...', NULL, 1),
(3113, 898, 10, NULL, 'literal', NULL, NULL, 'PHRLOC070', NULL, 1),
(3114, 898, 812, 815, 'resource', NULL, NULL, NULL, NULL, 1),
(3115, 899, 1, NULL, 'literal', NULL, NULL, '...wy zagen het monument nog midden in de kerk opgerigt...', NULL, 1),
(3116, 899, 10, NULL, 'literal', NULL, NULL, 'PHRLOC071', NULL, 1),
(3117, 899, 812, 815, 'resource', NULL, NULL, NULL, NULL, 1),
(3118, 900, 1, NULL, 'literal', NULL, NULL, '...trof ons zeer een schoon stuk in marmer verbeeldende het laatste oordeel... zyne fraaye tombe daar juist over, die van bisschop Wilhelm Antoon...', NULL, 1),
(3119, 900, 10, NULL, 'literal', NULL, NULL, 'PHRLOC072', NULL, 1),
(3120, 900, 812, 815, 'resource', NULL, NULL, NULL, NULL, 1),
(3121, 901, 1, NULL, 'literal', NULL, NULL, 'By deeze kerk is het opmerkingswaardig dat men onder het koor van de tegenwoordige nog de oude kerk vindt...', NULL, 1),
(3122, 901, 10, NULL, 'literal', NULL, NULL, 'PHRLOC073', NULL, 1),
(3123, 901, 812, 815, 'resource', NULL, NULL, NULL, NULL, 1),
(3124, 902, 1, NULL, 'literal', NULL, NULL, 'Ook de Jesuitenkerk moet een zeer fraay en bezienswaardig gebouw zyn...', NULL, 1),
(3125, 902, 10, NULL, 'literal', NULL, NULL, 'PHRLOC074', NULL, 1),
(3126, 902, 812, 815, 'resource', NULL, NULL, NULL, NULL, 1),
(3127, 903, 1, NULL, 'literal', NULL, NULL, '...hopende op deze wyze nog heden avond in Cassel te zyn hetgeen men ons hier verzekerd dat geschieden kan, dan Vriend lief ik geloof niet dat wy heden Cassel zullen zien...', NULL, 1),
