(3213, 939, 1, NULL, 'literal', NULL, NULL, '...intusschen wandelden wy derwaarts langs de beroemde Eexter grafkelder, door van Lier en zyne oudheidkundige brieven over Drente zoo naauwkeurig beschreven...', NULL, 1),
(3214, 939, 10, NULL, 'literal', NULL, NULL, 'PHROBJ001', NULL, 1),
