(3216, 940, 1, NULL, 'literal', NULL, NULL, '...naar het groote Hunnebed en de 2 drooge en natte kommen over al hetwelk gy de reis door Duitschland van Profr van Swinderen enz op bladz. 14 en 15 van het eerste deel kunt nazien.', NULL, 1),
(3217, 940, 10, NULL, 'literal', NULL, NULL, 'PHROBJ002', NULL, 1),
(3218, 940, 812, 914, 'resource', NULL, NULL, NULL, NULL, 1),
(3219, 941, 1, NULL, 'literal', NULL, NULL, 'Even voor Bentheim lieten wy de wagen naar de herberg ryden & wandelden langs eene zeer moerassige laan naar de Zwavelbron genoegzaam midden in het bosch gelegen...', NULL, 1),
(3220, 941, 10, NULL, 'literal', NULL, NULL, 'PHROBJ003', NULL, 1),
(3221, 941, 812, 915, 'resource', NULL, NULL, NULL, NULL, 1),
(3222, 942, 1, NULL, 'literal', NULL, NULL, '...wierden wy door het hooggelegene kasteel van Bentheim verrast schoon het nog een eind weg ervan af ligt...', NULL, 1),
(3223, 942, 10, NULL, 'literal', NULL, NULL, 'PHROBJ004', NULL, 1),
(3224, 942, 812, 916, 'resource', NULL, NULL, NULL, NULL, 1),
(3225, 943, 1, NULL, 'literal', NULL, NULL, 'Het kasteel bezigtigden wy slechts gedeeltelyk van binnen en om de bouwvalligheid van zommige delen, en wyl er weinig byzonders in het overige is...', NULL, 1),
(3226, 943, 10, NULL, 'literal', NULL, NULL, 'PHROBJ005', NULL, 1),
(3227, 943, 812, 916, 'resource', NULL, NULL, NULL, NULL, 1),
(3228, 944, 1, NULL, 'literal', NULL, NULL, '...aan de tegenovergestelde zyde is het grote stuk rots, Duivels oorkussen genoemd, waarop in vry duidelyke letters de woorden staan Hic Drusus dixit jura Tubantibus.', NULL, 1),
(3229, 944, 10, NULL, 'literal', NULL, NULL, 'PHROBJ006', NULL, 1),
(3230, 944, 812, 917, 'resource', NULL, NULL, NULL, NULL, 1),
(3231, 945, 1, NULL, 'literal', NULL, NULL, 'Het kabinet van de Graaf van Steinfurt vonden wy nog even als de Heere reizigers bovengemeld op bl 57&58 van het eerste deel schreven het is volstrekt een rommel zoo van alles door elkander waar ik behalve 3 a 4 goede schilderyen niets byzonders vond.', NULL, 1),
(3232, 945, 10, NULL, 'literal', NULL, NULL, 'PHROBJ007', NULL, 1),
(3233, 945, 812, 918, 'resource', NULL, NULL, NULL, NULL, 1),
(3234, 946, 1, NULL, 'literal', NULL, NULL, 'van hier wandelden wy gezamentlyk naar het Bagno zynde een lustplaats van den Graaf die thans te Parys is...', NULL, 1),
(3235, 946, 10, NULL, 'literal', NULL, NULL, 'PHROBJ008', NULL, 1),
(3236, 946, 812, 919, 'resource', NULL, NULL, NULL, NULL, 1),
(3237, 947, 1, NULL, 'literal', NULL, NULL, 'voorts vindt men hier nog een colossaal geheel op zich zelf staand waterrad van 102 voet diameter hetwelk het water op eenen toren brengt waardoor eene fontein ter hoogte van 80 voet met eene straal van 13 duim springt...', NULL, 1),
(3238, 947, 10, NULL, 'literal', NULL, NULL, 'PHROBJ009', NULL, 1),
(3239, 947, 812, 920, 'resource', NULL, NULL, NULL, NULL, 1),
(3240, 948, 1, NULL, 'literal', NULL, NULL, 'wy maakten een aanvang met het klooster der barmhartige broeders te bezien welk gesticht zyn oorsprong aan Clemens August verschuldigt is...', NULL, 1),
(3241, 948, 10, NULL, 'literal', NULL, NULL, 'PHROBJ010', NULL, 1),
(3242, 948, 812, 921, 'resource', NULL, NULL, NULL, NULL, 1),
(3243, 949, 1, NULL, 'literal', NULL, NULL, 'De groote Domkerk juist open ziende staan traden wy dezelve binnen: het is een schoon gebouw waar van veele sieraden van beeldhouwwerk enz zyn aangebragt...', NULL, 1),
(3244, 949, 10, NULL, 'literal', NULL, NULL, 'PHROBJ011', NULL, 1),
(3245, 949, 812, 922, 'resource', NULL, NULL, NULL, NULL, 1),
(3246, 950, 1, NULL, 'literal', NULL, NULL, '...hetgeen in dezelve voornaamlyk onze aandagt tot zich trok was de kapel waarin Barentje van Galen, heerschzuchtiger gedachtenis, begraven ligt waar altyd eene brandende lamp hangt; dezelve is door een zwaar metalen hek... van de kerk zelve afgescheiden, hy rust onder eene fraaye graftombe van zwart marmer waarop hy ook is afgebeeld...', NULL, 1),
(3247, 950, 10, NULL, 'literal', NULL, NULL, 'PHROBJ012', NULL, 1),
(3248, 950, 812, 923, 'resource', NULL, NULL, NULL, NULL, 1),
(3249, 951, 1, NULL, 'literal', NULL, NULL, '...verder vind men er nog eene schoone tombe van den Grave van Plettenberg, een zeer schoon & groot altaar & eenige restes van voormalige kostbaarheden.', NULL, 1),
(3250, 951, 10, NULL, 'literal', NULL, NULL, 'PHROBJ013', NULL, 1),
(3251, 951, 812, 924, 'resource', NULL, NULL, NULL, NULL, 1),
(3252, 952, 1, NULL, 'literal', NULL, NULL, 'Behalven den Dom zagen wy nog de Uberwasser & Lamberti kerken...', NULL, 1),
(3253, 952, 10, NULL, 'literal', NULL, NULL, 'PHROBJ014', NULL, 1),
(3254, 952, 812, 925, 'resource', NULL, NULL, NULL, NULL, 1),
